-- Verify
SELECT COUNT(*) AS updated_tiles,
       ROUND(AVG(hrc_score)::numeric, 3) AS avg_hrc,
       ROUND(MIN(hrc_score)::numeric, 3) AS min_hrc,
       ROUND(MAX(hrc_score)::numeric, 3) AS max_hrc
FROM hrc_tiles
WHERE methodology_version = 'v1.1'
  AND longitude BETWEEN -123.0 AND -121.2
  AND latitude  BETWEEN  37.0  AND  38.6;
